import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..", "..");
const webRoot = path.join(repoRoot, "dist", "web");
const outputPath = path.join(repoRoot, "src", "cli", "generated-embedded-assets.ts");

function renderEmbeddedAssetsModule(webAssets) {
  const lines = [
    "export interface EmbeddedWebAsset {",
    "  relativePath: string;",
    "  base64: string;",
    "}",
    "",
    "// This file is auto-generated by `bun run build:embedded-assets`.",
    "// Do not edit it manually.",
    "",
    "export const EMBEDDED_WEB_ASSETS: EmbeddedWebAsset[] = [",
  ];
  for (const asset of webAssets) {
    lines.push("  {");
    lines.push(`    relativePath: ${JSON.stringify(asset.relativePath)},`);
    lines.push(`    base64: ${JSON.stringify(asset.base64)},`);
    lines.push("  },");
  }
  lines.push("];");
  lines.push("");
  return lines.join("\n");
}

function walkFiles(rootDir) {
  const queue = [rootDir];
  const files = [];
  while (queue.length > 0) {
    const current = queue.shift();
    for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
      const nextPath = path.join(current, entry.name);
      if (entry.isDirectory()) {
        queue.push(nextPath);
        continue;
      }
      files.push(nextPath);
    }
  }
  return files.sort((left, right) => left.localeCompare(right));
}

let webAssets = [];
if (fs.existsSync(path.join(webRoot, "index.html"))) {
  webAssets = walkFiles(webRoot).map((filePath) => ({
    relativePath: path.relative(webRoot, filePath).replace(/\\/g, "/"),
    base64: fs.readFileSync(filePath).toString("base64"),
  }));
}
fs.writeFileSync(outputPath, renderEmbeddedAssetsModule(webAssets), "utf8");
